#include<stdio.h>
#include<stdlib.h>

int main()
{
	int i,temp=0,n,k,x,*arr;
	scanf("%d%d%d",&n,&k,&x);
	arr=malloc(n*sizeof(int));
	for(i=0;i<n;i++)
	{
		scanf("%d",&arr[i]);
	}
	for(i=n-k;i<n;i++)
	{
		arr[i]=x;
	}
	for(i=0;i<n;i++)
		temp+=arr[i];
	printf("%d\n",temp);
}

