use std::io;


fn main() {
    let mut line = String::new();
    io::stdin().read_line(&mut line).unwrap();
    let nkx : Vec<usize> = line.trim().split(" ").map(|x| x.parse::<usize>().unwrap()).collect();
    let (n, k, x) : (usize, usize, usize) = (nkx[0], nkx[1], nkx[2]);

    line = String::new();
    io::stdin().read_line(&mut line).unwrap();
    let my_deeds : Vec<usize> = line.trim().split(" ").map(|x| x.parse::<usize>().unwrap()).collect();

    let mut min_cost = 0;
    for i in 1..(n + 1) {
        if i <= k {
            min_cost += x;
        } else {
            min_cost += my_deeds[((n - i) as usize)];
        }
    }

    print!("{}", min_cost);
}
